// parties) does not have a strict majority. Since all seats are non-negative,
// no subset of eligible parties can do better.
ghost predicate NoValidCoalitionPossible(n: int, a: seq<int>)
  requires |a| == n >= 1
{
  EligibleSum(a) * 2 <= SumSeq(a)
}

