}

lemma EligibleSumStep(a: seq<int>, j: int)
  requires |a| >= 1
  requires 1 <= j < |a|
  ensures EligibleSum(a[..j+1]) ==
    (if a[j] * 2 <= a[0] then EligibleSum(a[..j]) + a[j] else EligibleSum(a[..j]))
{
