    invariant |coalition| >= 1
    invariant coalition[0] == 1
    invariant forall p | 0 <= p < |coalition| :: 1 <= coalition[p] <= j
    invariant forall p, q | 0 <= p < |coalition| && 0 <= q < |coalition| && p != q :: coalition[p] != coalition[q]
