ghost predicate IsValidCoalition(n: int, a: seq<int>, coalition: seq<int>)
  requires |a| == n >= 1
{
  (forall i | 0 <= i < |coalition| :: 1 <= coalition[i] <= n) &&
  (forall i, j | 0 <= i < |coalition| && 0 <= j < |coalition| && i != j :: coalition[i] != coalition[j]) &&
